import{_ as e,o as i,c as t,O as a}from"./chunks/framework.bdcb0ee1.js";const m=JSON.parse('{"title":"Custom Profile Fields","description":"","frontmatter":{},"headers":[],"relativePath":"administration/users/custom-fields.md","filePath":"administration/users/custom-fields.md","lastUpdated":1773167187000}'),s={name:"administration/users/custom-fields.md"},l=a('<h1 id="custom-profile-fields" tabindex="-1">Custom Profile Fields <a class="header-anchor" href="#custom-profile-fields" aria-label="Permalink to &quot;Custom Profile Fields&quot;">​</a></h1><p>Custom profile fields let you collect additional information from your members beyond the standard profile. Fields can be displayed alongside user posts in the mini profile area. You can manage them under the <strong>User Management</strong> navigation group in the Admin CP.</p><img width="1946" height="309" alt="image" src="https://github.com/user-attachments/assets/54dabe77-3b4c-437c-ba6b-530d11acd9e8"><nav class="table-of-contents"><ul><li><a href="#creating-a-field">Creating a field</a></li><li><a href="#field-types">Field types</a></li><li><a href="#mini-profile-display">Mini profile display</a></li><li><a href="#how-users-fill-in-fields">How users fill in fields</a></li><li><a href="#editing-and-deleting-fields">Editing and deleting fields</a></li></ul></nav><h2 id="creating-a-field" tabindex="-1">Creating a field <a class="header-anchor" href="#creating-a-field" aria-label="Permalink to &quot;Creating a field&quot;">​</a></h2><p>Click <strong>Create Field</strong> to add a new custom profile field. Each field has the following properties:</p><ul><li><strong>Handle</strong> — a unique internal identifier used to reference the field (letters, numbers, dashes and underscores only).</li><li><strong>Label</strong> — the display name shown to users when editing their profile.</li><li><strong>Sort Order</strong> — controls the order in which fields appear on the profile and in the mini profile.</li><li><strong>Show in Mini Profile</strong> — when enabled, the field value is displayed next to the user&#39;s posts.</li></ul><img width="1948" height="713" alt="image" src="https://github.com/user-attachments/assets/b65fb864-0dd7-4de6-8f8d-19f4d9dd588c"><h2 id="field-types" tabindex="-1">Field types <a class="header-anchor" href="#field-types" aria-label="Permalink to &quot;Field types&quot;">​</a></h2><p>Currently, custom profile fields support a <strong>single-line text</strong> input. Users can enter up to 255 characters per field.</p><h2 id="mini-profile-display" tabindex="-1">Mini profile display <a class="header-anchor" href="#mini-profile-display" aria-label="Permalink to &quot;Mini profile display&quot;">​</a></h2><p>Fields with <strong>Show in Mini Profile</strong> enabled are shown alongside every post a user makes, in the sidebar area next to their avatar and username. This is useful for fields like location, occupation or a favourite quote.</p><p>Fields appear in the mini profile in ascending order based on their <strong>Sort Order</strong> value.</p><h2 id="how-users-fill-in-fields" tabindex="-1">How users fill in fields <a class="header-anchor" href="#how-users-fill-in-fields" aria-label="Permalink to &quot;How users fill in fields&quot;">​</a></h2><p>Members can fill in their custom profile fields from the <strong>Edit Profile</strong> page. Each field appears with its label and a text input. Changes are saved alongside the rest of their profile information.</p><h2 id="editing-and-deleting-fields" tabindex="-1">Editing and deleting fields <a class="header-anchor" href="#editing-and-deleting-fields" aria-label="Permalink to &quot;Editing and deleting fields&quot;">​</a></h2><p>Click on any field in the list to update its properties. Deleting a field removes it from all user profiles — any responses that members have entered for that field are also removed.</p>',17),r=[l];function n(o,d,f,h,p,u){return i(),t("div",null,r)}const g=e(s,[["render",n]]);export{m as __pageData,g as default};
